                CreatedAt = now.AddDays(-1),
                EstimatedDelivery = now.AddDays(4),
                RecipientName = "Bob Smith",
                Description = "Furniture — 1 pallet"
            },
            new Shipment
            {
                TrackingNumber = "ST-100003",
                Origin = "Seattle, WA",
                Destination = "Denver, CO",
                Status = ShipmentStatus.Delivered,
                CreatedAt = now.AddDays(-7),
                EstimatedDelivery = now.AddDays(-2),
                RecipientName = "Carol Davis",
                Description = "Medical supplies — 5 boxes"
            },
            new Shipment
            {
                TrackingNumber = "ST-100004",
                Origin = "Houston, TX",
                Destination = "Phoenix, AZ",
                Status = ShipmentStatus.OutForDelivery,
                CreatedAt = now.AddDays(-2),
                EstimatedDelivery = now,
                RecipientName = "Dan Lee",
                Description = "Auto parts — 3 boxes"
            },
            new Shipment
            {
                TrackingNumber = "ST-100005",
                Origin = "Boston, MA",
                Destination = "Atlanta, GA",
                Status = ShipmentStatus.Delayed,
                CreatedAt = now.AddDays(-5),
                EstimatedDelivery = now.AddDays(1),
                RecipientName = "Eva Martinez",
                Description = "Clothing — 10 boxes"
            },
            new Shipment
            {
                TrackingNumber = "ST-100006",
                Origin = "San Francisco, CA",
                Destination = "Portland, OR",
                Status = ShipmentStatus.Pending,
                CreatedAt = now,
                EstimatedDelivery = now.AddDays(3),
                RecipientName = "Frank Wilson",
                Description = "Office equipment — 2 crates"
            }
        );

        await db.SaveChangesAsync();
    }
}

