@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Track Shipment</PageTitle>

<h2>📍 Shipment Tracking</h2>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else if (shipment is null)
{
    <div class="alert alert-warning mt-3">
        <strong>Not found.</strong> No shipment matches tracking number <code>@TrackingNumber</code>.
    </div>
}
else
{
    <div class="card mt-3 shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                    <p><strong>Recipient:</strong> @shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Description:</strong> @shipment.Description</p>
                    <p><strong>Shipped:</strong> @shipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                    <p>
                        <strong>Estimated Delivery:</strong>
                        @(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                    </p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDto? shipment;
    private bool loading = true;

    protected override async Task OnParametersSetAsync()
    {
        loading = true;
        shipment = await ShipmentService.GetByTrackingNumberAsync(TrackingNumber);
        loading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>🚚 Dispatcher Dashboard</h2>

<div class="row mb-3 align-items-end">
    <div class="col-md-4">
        <label class="form-label">Filter by status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-4">
        <label class="form-label">Search</label>
        <input type="text" class="form-control" placeholder="Tracking # or destination"
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-outline-secondary" @onclick="LoadShipments">
            🔄 Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments match the current filter.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@s.Status"
                                    @onchange="e => UpdateStatus(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(status == s.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert @(messageIsError ? "alert-danger" : "alert-success") mt-2">@message</div>
}

@code {
    private List<ShipmentDto> shipments = [];
    private bool loading = true;
    private string statusFilter = string.Empty;
    private string searchTerm = string.Empty;
    private string? message;
    private bool messageIsError;

    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
    {
        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var filter) && s.Status != filter)
            return false;
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase);
        }
        return true;
    });

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        message = null;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        loading = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
                message = $"Updated {shipment.TrackingNumber} to {newStatus}.";
                messageIsError = false;
            }
            else
            {
                message = $"Failed to update {shipment.TrackingNumber}.";
                messageIsError = true;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

