+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.Origin</td>
+                        <td>@s.Destination</td>
+                        <td>@s.RecipientName</td>
+                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
+                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</td>
+                        <td>
+                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
+                                    value="@s.Status"
+                                    @onchange="e => UpdateStatus(s, e)">
+                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                {
+                                    <option value="@status" selected="@(status == s.Status)">@status</option>
+                                }
+                            </select>
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+}
+
+@if (!string.IsNullOrEmpty(message))
+{
+    <div class="alert @(messageIsError ? "alert-danger" : "alert-success") mt-2">@message</div>
+}
+
+@code {
+    private List<ShipmentDto> shipments = [];
+    private bool loading = true;
+    private string statusFilter = string.Empty;
+    private string searchTerm = string.Empty;
+    private string? message;
+    private bool messageIsError;
+
+    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
+    {
+        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var filter) && s.Status != filter)
+            return false;
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+        {
+            var term = searchTerm.Trim();
+            return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
+                || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase);
+        }
+        return true;
+    });
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        loading = true;
+        message = null;
+        shipments = await ShipmentService.GetAllShipmentsAsync();
+        loading = false;
+    }
+
+    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
+    {
+        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
+        {
+            var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
+            if (success)
+            {
+                shipment.Status = newStatus;
+                message = $"Updated {shipment.TrackingNumber} to {newStatus}.";
+                messageIsError = false;
+            }
+            else
+            {
+                message = $"Failed to update {shipment.TrackingNumber}.";
+                messageIsError = true;
+            }
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.PickedUp => "bg-secondary",
+        ShipmentStatus.Pending => "bg-warning text-dark",
+        ShipmentStatus.Delayed => "bg-danger",
+        ShipmentStatus.Cancelled => "bg-dark",
+        _ => "bg-secondary"
+    };
+}
+

